{{
  (() => {
    const cart = appsmith.store.cart || [];

    const existingItem = cart.find(
      item => item.name === currentItem.name
    );

    if (existingItem) {
      if (existingItem.quantity >= Number(currentItem.stock)) {
        showAlert("현재 재고보다 많이 담을 수 없습니다.", "warning");
        return;
      }

      const updatedCart = cart.map(item =>
        item.name === currentItem.name
          ? {
              ...item,
              quantity: item.quantity + 1
            }
          : item
      );

      storeValue("cart", updatedCart);
    } else {
      storeValue("cart", [
        ...cart,
        {
          name: currentItem.name,
          price: Number(currentItem.price),
          quantity: 1,
          stock: Number(currentItem.stock)
        }
      ]);
    }

    showAlert("장바구니에 담았습니다.", "success");
  })()
}}

