export default {
  pollingId: "inventory_event_polling",

  start() {
    clearInterval(this.pollingId);

    setInterval(
      () => {
        this.checkEvent();
      },
      3000,
      this.pollingId
    );

    this.checkEvent();
  },

  async checkEvent() {
    try {
      const response = await GetLatestInventoryEvent.run();

      if (!response?.has_event || !response?.event) {
        return;
      }

      const event = response.event;

      const lastEventId = Number(
        appsmith.store.lastInventoryEventId || 0
      );

      if (Number(event.event_id) <= lastEventId) {
        return;
      }

      await storeValue(
        "lastInventoryEventId",
        Number(event.event_id)
      );

      const movementText =
        event.movement_type === "IN"
          ? "입고"
          : "출고";

      const message =
        `${event.product_name} ${event.quantity}개가 ` +
        `${movementText}되었습니다.`;

      await this.addLog({
        event_id: event.event_id,
        movement_type: event.movement_type,
        product_name: event.product_name,
        quantity: event.quantity,
        created_at: event.created_at,
        message: message
      });

      showAlert(
        message,
        event.movement_type === "IN"
          ? "success"
          : "info"
      );

      GetProducts.run();
      GetStock.run();
      GetExpiryProducts.run();

    } catch (error) {
      console.log(
        "입출고 이벤트 확인 실패:",
        error
      );
    }
  },

  async addLog(event) {
    const logs =
      appsmith.store.inventoryLogs || [];

    const newLog = {
      event_id: event.event_id,
      movement_type: event.movement_type,
      product_name: event.product_name,
      quantity: event.quantity,
      message: event.message,

      time: event.created_at
        ? new Date(event.created_at).toLocaleTimeString(
            "ko-KR"
          )
        : new Date().toLocaleTimeString("ko-KR")
    };

    const updatedLogs = [
      newLog,
      ...logs
    ].slice(0, 100);

    await storeValue(
      "inventoryLogs",
      updatedLogs
    );
  },

  stop() {
    clearInterval(this.pollingId);
  },

  clearLogs() {
    return storeValue(
      "inventoryLogs",
      []
    );
  }
}

